import{_ as t,o as e,c as r,a2 as n}from"./chunks/framework.BWuWLRhz.js";const u=JSON.parse('{"title":"纹理压缩格式","description":"","frontmatter":{},"headers":[],"relativePath":"图形学/纹理压缩.md","filePath":"图形学/纹理压缩.md","lastUpdated":null}'),o={name:"图形学/纹理压缩.md"};function s(l,a,i,c,h,p){return e(),r("div",null,[...a[0]||(a[0]=[n('<h1 id="纹理压缩格式" tabindex="-1">纹理压缩格式 <a class="header-anchor" href="#纹理压缩格式" aria-label="Permalink to &quot;纹理压缩格式&quot;">​</a></h1><p>BC代表块压缩，即是将纹理分块进行压缩，好处是可以更容易实现随机读取，只需要读取指定的块就行，而不需要全局解压。</p><h2 id="bc1" tabindex="-1">BC1 <a class="header-anchor" href="#bc1" aria-label="Permalink to &quot;BC1&quot;">​</a></h2><p>将纹理按4×4分块。<strong>假设</strong>在一个小块内，纹理的颜色变化是有限的。 <img src="https://raw.githubusercontent.com/xumyuan/image/master/20240703164417.png" alt="20240703164417"> 同时假设在一个块内，颜色的变化在RGB空间是线性的。（这也会有问题，可能同一块的颜色存在差异较大的可能，如果一个4×4的 block中包含红色、蓝色、绿色的三个像素，用BC1压缩后必然会有个颜色消失，因为这三种颜色在RGB空间中是无法拟合成一条直线的。） <img src="https://raw.githubusercontent.com/xumyuan/image/master/20240703164650.png" alt="20240703164650"><strong>压缩原理：</strong></p><ul><li>4字节 —— 从一块中找到两个颜色端点，每个颜色端点使用2字节存储，颜色通道分布为5:6:5</li><li>4字节 —— 将颜色以上述断点划分为4段，即共有四种颜色可供块内的像素选择，每个像素需要2位索引，共16*2/8=4字节</li></ul><p><strong>透明度存储：</strong> BC1可以存储一位的透明度，即0或255。 上述方法中，两端点的排布顺序并没有特别的要求，565的颜色值还可以被解释为16位的整数，可以通过改变顺序的方式来存储透明度。</p><ul><li>如果第一个端点大于第二个端点，按上述方案存储</li><li>如果第一个端点小于第二个端点，则颜色被等分为三段，第四段为黑色全透明。</li></ul><p>这样做可能导致在常规双线性插值时临界区域产生黑边。这可以通过将alpha阈值设置得高，从而剔除掉暗区，或者在着色器中将插值后的颜色除以插值后的alpha来避免，这将抵消变暗的效果。 <img src="https://raw.githubusercontent.com/xumyuan/image/master/20240703171629.png" alt="20240703171629"></p><h2 id="bc4" tabindex="-1">BC4 <a class="header-anchor" href="#bc4" aria-label="Permalink to &quot;BC4&quot;">​</a></h2><p>方案整体类似BC1，但是只用于灰度图。（使用高度图、光泽图等灰度图纹理） 两个端点各占8位，端点之间划分了8段，每个块内像素用三位编码。 透明度如果正序按上述方案，逆序则端点之间划分6段，剩余白色透明和黑色透明</p><h2 id="bc2-bc3-and-bc5" tabindex="-1">BC2, BC3, and BC5 <a class="header-anchor" href="#bc2-bc3-and-bc5" aria-label="Permalink to &quot;BC2, BC3, and BC5&quot;">​</a></h2><p>这几个方案本质是前两个方案的组合 <strong>BC3:</strong> 存储RGBA数据，使用BC1存储RGB通道，使用BC4存储A通道。块总大小为16字节，平均每像素1字节。是需要完整Alpha通道的纹理最长与的格式。或者用于将彩色纹理和灰度图打包。 <strong>BC5:</strong> 双通道格式数据，每个通道使用一个BC4存储。块总大小为16字节，平均每像素1字节。如果存储X,Y可以重建出Z。适合切线空间的法线贴图。有更高的保真度，缺点是内存翻倍。 <strong>BC2:</strong> 存储RGBA数据，RGB使用BC1，Alpha通道每像素使用4位，固定的4位，即共代表16中不同的透明度。总大小和BC3一样，共16字节，但是效果不如BC3，很少用。</p><h2 id="bc6-and-bc7" tabindex="-1">BC6 and BC7 <a class="header-anchor" href="#bc6-and-bc7" aria-label="Permalink to &quot;BC6 and BC7&quot;">​</a></h2><p>压缩对比及使用场景 <img src="https://raw.githubusercontent.com/xumyuan/image/master/20240703175256.png" alt="20240703175256"></p>',14)])])}const B=t(o,[["render",s]]);export{u as __pageData,B as default};
